  const yp1 = vec3(0, yHalf, 0);
  const yt1 = mx_noise_float(yp1);
  const yp2 = vec3(0, pos.y, 0);
  const yt2r = mx_noise_float(yp2);
  const yt2 = mul(yt2r, 0.5);
  const yDbl = mul(pos.y, 2);
  const yp3 = vec3(1, yDbl, 1);
