  const yt3 = mul(yt3r, 0.25);
  const ytS12 = add(yt1, yt2);
  const ytAll = add(ytS12, yt3);
  const turbStr = mul(ytAll, turbulence);
  const turbAbs = abs(turbStr);
  const xturb = mul(turbAbs, 5);

